import { PrismaClient } from "@prisma/client";
import { createPool } from "mysql2/promise";
import { PrismaMySql } from "@tidbcloud/prisma-adapter";

const globalForPrisma = global as unknown as { prisma: PrismaClient };

async function createPrismaCli() {
  const pool = await createPool({
    uri: process.env.DATABASE_URL,
  });

  const adapter = new PrismaMySql(pool);
  return new PrismaClient({ adapter });
}

let prisma: PrismaClient | Promise<PrismaClient>;

if (globalForPrisma.prisma) {
  prisma = globalForPrisma.prisma;
} else {
  prisma = createPrismaCli();
  if (!globalForPrisma.prisma) {
    globalForPrisma.prisma = prisma as any;
  }
}

export async function getPrismaDb(): Promise<PrismaClient> {
  if (prisma instanceof Promise) {
    return await prisma;
  }
  return prisma;
}

export const db = globalForPrisma.prisma || (createPrismaCli() as any);
